# src/payments/payment_service.py
from .gateway import Gateway
from .ledger import Ledger

class PaymentService:
    def __init__(self, gateway, ledger, guard, metrics, events):
        self.gateway = gateway
        self.ledger = ledger
        self.guard = guard
        self.metrics = metrics
        self.events = events

    def authorize(self, amount, ctx):
        key = f"txn:{ctx.order_id}:authorize:{ctx.attempt}"
        validated = self.guard.check(ctx, "authorize")
        if not validated.ok:
            self.metrics.increment("authorize.rejected", reason=validated.reason)
            return Result(ok=False, reason=validated.reason)
        res = self.gateway.send(op="authorize", amount=amount, idempotency_key=key)
        self.ledger.record(ctx.order_id, "authorize", amount, res.id)
        self.events.emit("authorize.done", order_id=ctx.order_id, txn_id=res.id)
        return Result(ok=True, id=res.id)

